import {
  Comment,
  cloneVNode,
  computed,
  getCurrentInstance,
  h,
  ref,
  renderSlot,
  unref,
  watchEffect,
} from 'vue'
import { debugWarn, isArray, isUndefined } from '@element-plus/utils'
import { useNamespace } from '@element-plus/hooks'
import {
  cellForced,
  defaultRenderCell,
  getDefaultClassName,
  treeCellPrefix,
} from '../config'
import { getAutoColumnWidth } from '../column-width'
import { parseMinWidth, parseWidth } from '../util'
import { ghostRowKey, ghostRowSign } from '../private'
import GhostRowAddButton from '../ghost-row-add-button.vue'

import type { ComputedRef, RendererNode, Slots, VNode } from 'vue'
import type { TableColumn, TableColumnCtx } from './defaults'
import type { DefaultRow, Table } from '../table/defaults'

const isEmptyRequiredValue = (value: unknown) =>
  value === '' || value === null || value === undefined

const hasGhostRowValue = <T extends DefaultRow>(row: T) => {
  return Object.entries(row ?? {}).some(([key, value]) => {
    if (key === ghostRowSign || key === ghostRowKey) return false
    return !isEmptyRequiredValue(value)
  })
}

const isElInputVNode = (vnode: VNode) => {
  const type = vnode.type as { name?: string; __name?: string }
  return type?.name === 'ElInput' || type?.__name === 'ElInput'
}

const applyRequiredInputState = <T extends DefaultRow>(
  vnodes: VNode | VNode[],
  column: TableColumnCtx<T>,
  row: T
) => {
  if (!column.required || !column.property) return vnodes
  if (row?.[ghostRowSign] && !hasGhostRowValue(row)) return vnodes
  if (!isEmptyRequiredValue(row?.[column.property])) return vnodes

  const patchVNode = (vnode: VNode) => {
    if (!isElInputVNode(vnode)) return vnode

    const vnodeProps = (vnode.props ?? {}) as Record<string, any>

    return cloneVNode(vnode, {
      inputType: vnodeProps.inputType ?? vnodeProps['input-type'] ?? 'error',
      infoTip: vnodeProps.infoTip ?? vnodeProps['info-tip'] ?? 'Required',
    })
  }

  return isArray(vnodes)
    ? vnodes.map((vnode) => patchVNode(vnode))
    : patchVNode(vnodes)
}

function useRender<T extends DefaultRow>(
  props: TableColumnCtx<T>,
  slots: Slots,
  owner: ComputedRef<Table<T>>
) {
  const instance = getCurrentInstance() as TableColumn<T>
  const columnId = ref('')
  const isSubColumn = ref(false)
  const realAlign = ref<string | null>()
  const realHeaderAlign = ref<string | null | undefined>()
  const ns = useNamespace('table')
  watchEffect(() => {
    realAlign.value = props.align ? `is-${props.align}` : null
    // nextline help render
    realAlign.value
  })
  watchEffect(() => {
    realHeaderAlign.value = props.headerAlign
      ? `is-${props.headerAlign}`
      : realAlign.value
    // nextline help render
    realHeaderAlign.value
  })
  const columnOrTableParent = computed<Table<T> | TableColumn<T>>(() => {
    let parent: any = instance.vnode.vParent || instance.parent
    while (parent && !parent.tableId && !parent.columnId) {
      parent = parent.vnode.vParent || parent.parent
    }
    return parent
  })
  const hasTreeColumn = computed<boolean>(() => {
    const { store } = (instance.parent as Table<T>)!
    if (!store) return false
    const { treeData } = store.states
    const treeDataValue = treeData.value
    return treeDataValue && Object.keys(treeDataValue).length > 0
  })

  const realWidth = ref(parseWidth(props.width))
  const realMinWidth = ref(parseMinWidth(props.minWidth))
  const setColumnWidth = (column: TableColumnCtx<T>) => {
    if (realWidth.value) column.width = realWidth.value
    if (realMinWidth.value) {
      column.minWidth = realMinWidth.value
    }
    if (!realWidth.value && realMinWidth.value) {
      column.width = undefined
    }
    column.autoWidth =
      isUndefined(column.width) && !realWidth.value && !realMinWidth.value
    if (column.autoWidth) {
      column.minWidth = getAutoColumnWidth(column.label)
    } else if (!column.minWidth) {
      column.minWidth = 80
    }
    column.realWidth = Number(
      isUndefined(column.width) ? column.minWidth : column.width
    )
    return column
  }
  const setColumnForcedProps = (column: TableColumnCtx<T>) => {
    // some props are locked for specific column types
    const type = column.type
    const source = cellForced[type as keyof typeof cellForced] || {}
    Object.keys(source).forEach((prop) => {
      const value = source[prop as keyof typeof source]
      if (prop !== 'className' && !isUndefined(value)) {
        ;(column as any)[prop] = value
      }
    })
    const className = getDefaultClassName(type)
    if (className) {
      const forceClass = `${unref(ns.namespace)}-${className}`
      column.className = column.className
        ? `${column.className} ${forceClass}`
        : forceClass
    }
    return column
  }

  const checkSubColumn = (children: VNode | VNode[]) => {
    if (isArray(children)) {
      children.forEach((child) => check(child))
    } else {
      check(children)
    }
    function check(item: any) {
      if (item?.type?.name === 'ElTableColumn') {
        item.vParent = instance
      }
    }
  }
  const setColumnRenders = (column: TableColumnCtx<T>) => {
    // renderHeader is not recommended.
    //@ts-expect-error
    if (props.renderHeader) {
      debugWarn(
        'TableColumn',
        'Comparing to render-header, scoped-slot header is easier to use. We recommend users to use scoped-slot header.'
      )
    } else if (column.type !== 'selection') {
      column.renderHeader = (scope) => {
        // help render
        instance.columnConfig.value['label']
        const fallbackContent = [
          h(
            'span',
            {
              class: ['cell-span'],
            },
            [column.label]
          ),
        ]
        return renderSlot(slots, 'header', scope, () => fallbackContent)
      }
    }

    if (slots['filter-icon']) {
      column.renderFilterIcon = (scope) => {
        return renderSlot(slots, 'filter-icon', scope)
      }
    }

    if (slots.expand) {
      column.renderExpand = (scope) => {
        return renderSlot(slots, 'expand', scope)
      }
    }

    const editSlot = slots['edit-cell']

    if (editSlot) {
      column.renderEditCell = (scope) => {
        return editSlot(scope)
      }
    }

    let originRenderCell = column.renderCell
    // TODO: refine this implementation
    if (column.type === 'expand') {
      // expanded rows do not allow a custom renderCell; wrap the existing one.
      column.renderCell = (data) =>
        h(
          'div',
          {
            class: 'cell',
          },
          [originRenderCell(data)]
        )
      owner.value.renderExpanded = (row) => {
        return slots.default ? slots.default(row) : slots.default
      }
    } else {
      originRenderCell = originRenderCell || defaultRenderCell
      // wrap renderCell
      column.renderCell = (data) => {
        let children: VNode | VNode[] | null = null
        const { columns } = owner.value.store.states
        const columnCount = columns.value.length
        const shouldRenderAddButton =
          owner.value.props.ghostTable &&
          owner.value.props.editTable &&
          !!data.row?.[ghostRowSign] &&
          (columnCount === 1
            ? data.cellIndex === 0
            : data.cellIndex === columnCount - 1)
        const shouldRenderEditCell =
          owner.value.props.ghostTable &&
          owner.value.props.editTable &&
          !!column.renderEditCell

        if (shouldRenderAddButton) {
          children = [
            h(GhostRowAddButton, {
              row: data.row,
            }),
          ]
        } else if (shouldRenderEditCell) {
          const vnodes = applyRequiredInputState(
            column.renderEditCell!(data),
            column,
            data.row
          )
          const editVNodes = isArray(vnodes) ? vnodes : [vnodes]
          children = editVNodes.some((v) => v.type !== Comment)
            ? vnodes
            : originRenderCell(data)
        } else if (slots.default) {
          const vnodes = slots.default(data)
          const defaultVNodes = isArray(vnodes) ? vnodes : [vnodes]
          children = defaultVNodes.some((v) => v.type !== Comment)
            ? vnodes
            : originRenderCell(data)
        } else {
          children = originRenderCell(data)
        }
        const firstUserColumnIndex = columns.value.findIndex(
          (item) => item.type === 'default'
        )
        const shouldCreatePlaceholder =
          hasTreeColumn.value &&
          !data.row?.[ghostRowSign] &&
          data.cellIndex === firstUserColumnIndex
        const prefix = treeCellPrefix(data, shouldCreatePlaceholder)
        const props = {
          class: 'cell',
          style: {},
          rowIndex: data.$index,
          cellIndex: data.cellIndex,
        }
        if (column.showOverflowTooltip) {
          props.class = `${props.class} ${unref(ns.namespace)}-tooltip`
          props.style = {
            width: `${
              (data.column.realWidth || Number(data.column.width)) - 1
            }px`,
          }
        }
        if (owner.value.props.ghostTable) {
          props.class = `${props.class} is-full-width`
        }
        checkSubColumn(children)
        return h('div', props, [prefix, children])
      }
    }
    return column
  }
  const getPropsData = (...propsKey: string[][]) => {
    return propsKey.reduce(
      (prev, cur) => {
        if (isArray(cur)) {
          cur.forEach((key) => {
            prev[key] = props[key as keyof TableColumnCtx<T>]
          })
        }
        return prev
      },
      {} as Record<string, any>
    )
  }
  const getColumnElIndex = (children: T[], child: RendererNode | null) => {
    return Array.prototype.indexOf.call(children, child)
  }

  const updateColumnOrder = () => {
    owner.value.store.commit('updateColumnOrder', instance.columnConfig.value)
  }

  return {
    columnId,
    realAlign,
    isSubColumn,
    realHeaderAlign,
    columnOrTableParent,
    setColumnWidth,
    setColumnForcedProps,
    setColumnRenders,
    getPropsData,
    getColumnElIndex,
    updateColumnOrder,
  }
}

export default useRender
